public void matchConstraint(ObjectType constraintObj) {
    // We only want to match contraints on anonymous types.

    // Handle the case where the constraint object is a record type.
    //
    // param constraintObj {{prop: (number|undefined)}}
    // function f(constraintObj) {}
    // f({});
    //
    // We want to modify the object literal to match the constraint, by
    // taking any each property on the record and trying to match
    // properties on this object.
    if (constraintObj.isRecordType()) {
      for (String prop : constraintObj.getOwnPropertyNames()) {
        JSType propType = constraintObj.getPropertyType(prop);
        if (!isPropertyTypeDeclared(prop)) {
          JSType typeToInfer = propType;
          if (!hasProperty(prop)) {
            typeToInfer = getNativeType(JSTypeNative.VOID_TYPE)
                .getLeastSupertype(propType);
          }
          defineInferredProperty(prop, typeToInfer, null);
        }
      }
    } else if (constraintObj.isEnumType()) {
      // Handle enum types by applying the enum element type
      JSType elementType = constraintObj.toMaybeEnumType().getElementsType();
      if (elementType != null) {
        for (String prop : constraintObj.getOwnPropertyNames()) {
          if (!isPropertyTypeDeclared(prop)) {
            JSType typeToInfer = elementType;
            if (!hasProperty(prop)) {
              typeToInfer = getNativeType(JSTypeNative.VOID_TYPE)
                  .getLeastSupertype(elementType);
            }
            defineInferredProperty(prop, typeToInfer, null);
          }
        }
      }
    }
  }
